#include<bits/stdc++.h>
using namespace std;
vector<pair<long long,long long>> mp[2501];
long long dis[2501],n,m;
bool vis[2501];
void dijkstra()
{
	memset(dis,0x3f,sizeof(dis));
	dis[1]=0;
	for(long long i=1;i<=n;i++)
	{
		long long min1=LONG_LONG_MAX,min2;
		for(long long j=1;j<=n;j++)
		{
			if(!vis[j]&&dis[j]<min1)
			{
				min1=dis[j];
				min2=j;
			}
		}
		vis[min2]=1;
		for(pair<long long,long long> j:mp[min2])
		{
			if(!vis[j.first]&&dis[min2]+j.second<dis[j.first])
			{
				dis[j.first]=dis[min2]+j.second;
			}
		}
	}
}
void spfa()
{
	queue<int> q;
	q.push(1);
	memset(dis,0x3f,sizeof(dis));
	dis[1]=0;
	while(!q.empty())
	{
		int t=q.front();
		q.pop();
		vis[t]=0;
		for(pair<int,int> i:mp[t])
		{
			int v=i.first;
			if(dis[v]>dis[t]+i.second)
			{
				dis[v]=dis[t]+i.second;
				if(!vis[v])
				{
					vis[v]=1;
					q.push(v);
				}
			}
		}
	}
}
int main()
{
	scanf("%lld%lld",&n,&m);
	for(long long i=1;i<=m;i++)
	{
		long long a,b,c;
		scanf("%lld%lld%lld",&a,&b,&c);
		mp[a].push_back(make_pair(b,c));
		mp[b].push_back(make_pair(a,c));
	}
	spfa();
	printf("%lld",dis[n]);
	return 0;
}
